// scroll.js
function smoothScroll(classSelector) {
    // Obtener todos los hipervínculos con la clase "scroll-link"
    const scrollLinks = document.querySelectorAll(classSelector);

    // Agregar un controlador de eventos para cada hipervínculo
    scrollLinks.forEach((link) => {
      link.addEventListener("click", (event) => {
        // Prevenir el comportamiento predeterminado del hipervínculo
        event.preventDefault();

        // Obtener el valor del atributo href del hipervínculo
        const href = link.getAttribute("href");

        // Obtener el elemento al que apunta el hipervínculo
        const targetElement = document.querySelector(href);

        // Hacer scroll suavemente hacia el elemento
        targetElement.scrollIntoView({ behavior: "smooth" });
      });
    });
  }

module.exports = {
    smoothScroll
};
